#include<bits/stdc++.h>
using namespace std;
long long n,d,e;
int main()
{
	long long t;
	cin>>t;
	while(t--){
		cin>>n>>d>>e;
		long long k=n-e*d+2;
		long long l=1,r=k/2;
		while(l<r){
			long long mid=(r+l)/2;
			if(mid*(k-mid)>=n)r=mid;
			else l=mid+1;
//			cout<<l<<" "<<r<<"\n";
		}
		if(r*(k-r)==n)cout<<r<<" "<<n/r<<"\n";
		else cout<<"NO\n";
	}
}
